DROP TABLE IF EXISTS `folder_check_files`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `folder_check_files` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `file_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `folder_id` int(10) unsigned NOT NULL COMMENT '文件夹id',
  `check_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '检测项目',
  `check_type` tinyint(4) NOT NULL DEFAULT '2' COMMENT '1 需要检测  2 上传就通过',
  `check_text` varchar(1000) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '检测内容',
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `folder_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `standard_id` int(11) DEFAULT NULL COMMENT '准则ID(1-6)',
  `master_id` int(10) unsigned NOT NULL DEFAULT '0',
  `audit_status` tinyint(4) DEFAULT '0' COMMENT '审核状态',
  PRIMARY KEY (`id`),
  KEY `master_id` (`master_id`)
) ENGINE=InnoDB AUTO_INCREMENT=293 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
